List<AlgeriaLocation> getCommunesByWilayaId(int wilayaId) => algerianCommunes[wilayaId] ?? [];
List<AlgeriaLocation> getCommunesByWilayaName(String wilayaName) {
  final wilaya = algerianWilayas.firstWhere((w) => w.name == wilayaName, orElse: () => algerianWilayas.first);
  return algerianCommunes[wilaya.id] ?? [];
}